            color: #f59e0b;
            padding: 4px 10px;
            border-radius: 20px;
            font-size: 11px;
            font-weight: 600;
            display: inline-block;
        }

        .dataTables_wrapper {
            color: white;
        }

        .dataTables_wrapper .dataTables_length,
