            width: 36px;
            height: 36px;
            border-radius: 10px;
            background: linear-gradient(135deg, #C850C0, #4158D0);
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 18px;
            color: white;
            flex-shrink: 0;
        }

        .header-title {
            font-size: 14px;
            font-weight: 700;
            color: white;
