                                        echo "<td>" . htmlspecialchars($pagamento['idpagamento'] ?? '') . "</td>";
                                        echo "<td>R$ " . number_format($pagamento['valor'], 2, ',', '.') . "</td>";
                                        echo "<td>" . htmlspecialchars($pagamento['texto'] ?? '') . "</td>";
                                        echo "<td>" . htmlspecialchars($pagamento['data'] ?? '') . "</td>";
                                        echo "<td>" . $status . "</td>";
                                        echo "</tr>";
